+		'h', 'e', 'l', 'l', 'o',
+	}
+
+	r := bytes.NewReader(data)
+	msgType, payload, err := ReadMessage(r)
+	if err != nil {
+		t.Fatalf("ReadMessage failed: %v", err)
+	}
+
+	if msgType != MsgData {
+		t.Errorf("got type %d, want %d", msgType, MsgData)
